commands.syntax:
BEGIN;
-- SQL statements
COMMIT; -- atau ROLLBACK;

commands.examples:
BEGIN;
UPDATE accounts SET balance = balance - 1000 WHERE id = 1;
UPDATE accounts SET balance = balance + 1000 WHERE id = 2;
COMMIT;

-- Membatalkan
BEGIN;
DELETE FROM important_data;
ROLLBACK; -- data tidak terhapus

commands.syntax:
SAVEPOINT nama;
ROLLBACK TO SAVEPOINT nama;
RELEASE SAVEPOINT nama;

commands.examples:
BEGIN;
INSERT INTO orders (user_id, total) VALUES (1, 50000);
SAVEPOINT sp1;
INSERT INTO order_items (order_id, product_id) VALUES (1, 999); -- error misalnya
ROLLBACK TO SAVEPOINT sp1; -- hanya rollback item, order tetap
COMMIT;

BEGIN ISOLATION LEVEL SERIALIZABLE;
SELECT * FROM inventory WHERE product_id = 1;
-- di transaction lain tidak bisa mengubah data ini
UPDATE inventory SET stock = stock - 1 WHERE product_id = 1;
COMMIT;

-- Lihat level saat ini
SHOW transaction_isolation;

-- Pastikan hanya satu process yang menjalankan job
SELECT pg_try_advisory_lock(12345);
-- Jika return true, jalankan job
-- ...
SELECT pg_advisory_unlock(12345);
